// app/api/air-quality/route.ts
import { NextRequest, NextResponse } from "next/server";
import { cityMapping } from "../../../lib/cityMapping"; // relative path

export async function GET(req: NextRequest) {
  const token = process.env.WAQI_API_TOKEN;
  if (!token)
    return NextResponse.json({ error: "Missing token" }, { status: 500 });

  const city = req.nextUrl.searchParams.get("city") || "";
  const cityQuery = cityMapping[city as keyof typeof cityMapping] || city;
  const encodedCity = encodeURIComponent(cityQuery);

  try {
    const res = await fetch(
      `https://api.waqi.info/feed/${encodedCity}/?token=${token}`,
    );
    const data = await res.json();

    if (data.status !== "ok") return NextResponse.json({ error: data.status });

    return NextResponse.json(data.data);
  } catch (err) {
    return NextResponse.json({ error: "Fetch failed" }, { status: 500 });
  }
}
